'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import CartSidebar from '@/components/sidebars/CartSidebar'
import UserSidebar from '@/components/sidebars/UserSidebar'

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false)
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)
  const [cartOpen, setCartOpen] = useState(false)
  const [userOpen, setUserOpen] = useState(false)

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50)
    }
    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  return (
    <>
      <nav 
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
          scrolled 
            ? 'bg-branco/95 backdrop-blur-xl py-4 shadow-lg' 
            : 'bg-transparent py-6'
        }`}
      >
        <div className="max-w-[1600px] mx-auto px-8 flex justify-between items-center">
          {/* Logo */}
          <Link href="/" className="font-display text-2xl font-semibold text-preto tracking-wider">
            BABEL
          </Link>

          {/* Desktop Menu */}
          <ul className="hidden md:flex gap-12 items-center">
            <li>
              <Link 
                href="#collections" 
                className="text-preto text-sm font-medium tracking-wide hover:text-cinza transition-colors relative group"
              >
                Collections
                <span className="absolute -bottom-1 left-0 w-0 h-[2px] bg-cinza group-hover:w-full transition-all duration-300" />
              </Link>
            </li>
            <li>
              <Link 
                href="/pages/consultancy" 
                className="text-preto text-sm font-medium tracking-wide hover:text-cinza transition-colors relative group"
              >
                Consultancy
                <span className="absolute -bottom-1 left-0 w-0 h-[2px] bg-cinza group-hover:w-full transition-all duration-300" />
              </Link>
            </li>
            <li>
              <Link 
                href="/pages/about" 
                className="text-preto text-sm font-medium tracking-wide hover:text-cinza transition-colors relative group"
              >
                About
                <span className="absolute -bottom-1 left-0 w-0 h-[2px] bg-cinza group-hover:w-full transition-all duration-300" />
              </Link>
            </li>
          </ul>

          {/* Icons */}
          <div className="flex items-center gap-6">
            <button 
              onClick={() => setCartOpen(true)}
              className="relative hover:-translate-y-1 transition-transform"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
              </svg>
              <span className="absolute -top-2 -right-2 bg-cinza text-branco text-xs w-5 h-5 rounded-full flex items-center justify-center font-semibold">
                0
              </span>
            </button>
            <button 
              onClick={() => setUserOpen(true)}
              className="hover:-translate-y-1 transition-transform"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
              </svg>
            </button>

            {/* Hamburger */}
            <button 
              className="md:hidden flex flex-col gap-1.5 w-7"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            >
              <span className={`h-[2px] bg-preto transition-all ${mobileMenuOpen ? 'rotate-45 translate-y-2' : ''}`} />
              <span className={`h-[2px] bg-preto transition-all ${mobileMenuOpen ? 'opacity-0' : ''}`} />
              <span className={`h-[2px] bg-preto transition-all ${mobileMenuOpen ? '-rotate-45 -translate-y-2' : ''}`} />
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        <div 
          className={`md:hidden fixed top-0 right-0 w-4/5 h-screen bg-branco shadow-2xl transition-transform duration-300 ${
            mobileMenuOpen ? 'translate-x-0' : 'translate-x-full'
          }`}
        >
          <ul className="flex flex-col gap-8 p-12 pt-24">
            <li>
              <Link 
                href="#collections" 
                className="text-preto text-xl font-medium tracking-wide"
                onClick={() => setMobileMenuOpen(false)}
              >
                Collections
              </Link>
            </li>
            <li>
              <Link 
                href="/pages/consultancy" 
                className="text-preto text-xl font-medium tracking-wide"
                onClick={() => setMobileMenuOpen(false)}
              >
                Consultancy
              </Link>
            </li>
            <li>
              <Link 
                href="/pages/about" 
                className="text-preto text-xl font-medium tracking-wide"
                onClick={() => setMobileMenuOpen(false)}
              >
                About
              </Link>
            </li>
          </ul>
        </div>
      </nav>

      {/* Sidebars */}
      <CartSidebar isOpen={cartOpen} onClose={() => setCartOpen(false)} />
      <UserSidebar isOpen={userOpen} onClose={() => setUserOpen(false)} />
    </>
  )
}